proc graphemeBreakKind*(cp: int32): GraphemeBreakKind =
  var lo = 0
  var hi = gbpTable.len - 1
  while lo <= hi:
    let mid = (lo + hi) shr 1
    if cp < gbpTable[mid].lo:
      hi = mid - 1
    elif cp > gbpTable[mid].hi:
      lo = mid + 1
    else:
      return GraphemeBreakKind(gbpTable[mid].cls)
  return gbOther
